/**
 * Feature Video Tabs Section
 * Full-width video showcase with tabbed navigation
 * Author: generated by Amazon Q
 * Created: 2024-01-20
 */

'use client';

import { useState, useRef, useEffect } from 'react';

interface VideoTab {
  id: string;
  title: string;
  icon?: string;
  videoSrc: string;
  videoSrcMobile?: string;
}

interface FeatureVideoTabsSectionProps {
  backgroundImage?: string;
  tabs: VideoTab[];
  showFullscreenButton?: boolean;
  autoplay?: boolean;
  maxWidth?: string;
  paddingY?: string;
  paddingX?: string;
}

export default function FeatureVideoTabsSection({
  backgroundImage,
  tabs = [],
  showFullscreenButton = true,
  autoplay = true,
  maxWidth = '1920px',
  paddingY = '0',
  paddingX = '0',
}: FeatureVideoTabsSectionProps) {
  const [activeTab, setActiveTab] = useState(0);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [openAccordion, setOpenAccordion] = useState<number | null>(0);
  const videoRefs = useRef<(HTMLVideoElement | null)[]>([]);

  useEffect(() => {
    const video = videoRefs.current[activeTab];
    if (!video || !autoplay) return;

    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          video.play().catch(() => {});
        } else {
          video.pause();
        }
      },
      { threshold: 0.3 }
    );

    observer.observe(video);
    return () => observer.disconnect();
  }, [activeTab, autoplay]);

  const handleTabClick = (index: number) => {
    setActiveTab(index);
    videoRefs.current.forEach((video, idx) => {
      if (video) {
        if (idx === index) {
          video.currentTime = 0;
          video.play().catch(() => {});
        } else {
          video.pause();
        }
      }
    });
  };

  const handleAccordionClick = (index: number) => {
    setOpenAccordion(openAccordion === index ? null : index);
  };

  const handleFullscreen = () => {
    const video = videoRefs.current[activeTab];
    if (!video) return;

    if (!document.fullscreenElement) {
      video.requestFullscreen().catch(() => {});
      setIsFullscreen(true);
    } else {
      document.exitFullscreen();
      setIsFullscreen(false);
    }
  };

  return (
    <section 
      className="relative w-full bg-slate-50 dark:bg-slate-950 overflow-hidden"
      style={{
        paddingTop: paddingY,
        paddingBottom: paddingY,
      }}
    >
      <div 
        className="container-fluid mx-auto"
        style={{ 
          maxWidth,
          paddingLeft: paddingX,
          paddingRight: paddingX,
        }}
      >
        <div 
          className="relative rounded-none md:rounded-3xl overflow-hidden -mx-4 md:mx-0"
          style={{
            backgroundImage: backgroundImage ? `url(${backgroundImage})` : undefined,
            backgroundPosition: 'center',
            backgroundSize: 'cover',
          }}
        >
          {/* Desktop Tabs */}
          <div className="hidden md:flex items-center justify-center gap-2 lg:gap-4 px-4 lg:px-8 py-6 lg:py-8 bg-white/80 dark:bg-slate-900/80 backdrop-blur-sm border-b border-slate-200 dark:border-slate-700">
            {tabs.map((tab, index) => (
              <button
                key={tab.id}
                onClick={() => handleTabClick(index)}
                className={`flex items-center gap-2 lg:gap-3 px-4 lg:px-6 py-3 lg:py-4 rounded-xl lg:rounded-2xl transition-all duration-300 ${
                  activeTab === index
                    ? 'bg-gradient-to-br from-cyan-500 to-violet-500 text-white shadow-lg shadow-cyan-500/30 scale-105'
                    : 'bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700 hover:scale-102 border border-slate-200 dark:border-slate-700'
                }`}
              >
                {tab.icon && (
                  <img src={tab.icon} alt={tab.title} className="w-5 h-5 lg:w-6 lg:h-6" />
                )}
                <span className="font-semibold text-sm lg:text-base whitespace-nowrap">{tab.title}</span>
              </button>
            ))}
          </div>

          {/* Mobile Accordion */}
          <div className="md:hidden bg-white/80 dark:bg-slate-900/80 backdrop-blur-sm">
            {tabs.map((tab, index) => (
              <div key={tab.id} className="border-b border-slate-200 dark:border-slate-700">
                <button
                  onClick={() => handleAccordionClick(index)}
                  className="w-full flex items-center justify-between px-4 py-4 text-left hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors"
                >
                  <div className="flex items-center gap-3">
                    {tab.icon && (
                      <img src={tab.icon} alt={tab.title} className="w-5 h-5" />
                    )}
                    <span className="font-semibold text-slate-900 dark:text-white">{tab.title}</span>
                  </div>
                  <svg
                    className={`w-5 h-5 text-slate-500 transition-transform ${
                      openAccordion === index ? 'rotate-180' : ''
                    }`}
                    fill="none"
                    stroke="currentColor"
                    viewBox="0 0 24 24"
                  >
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
                  </svg>
                </button>
                {openAccordion === index && (
                  <div className="px-4 pb-4">
                    <div className="relative aspect-video rounded-lg overflow-hidden bg-black">
                      {(() => {
                        const videoSrc = tab.videoSrcMobile || tab.videoSrc;
                        const videoSrcString = typeof videoSrc === 'string' ? videoSrc : (videoSrc as any)?.src || '';
                        const videoObjectFit = typeof videoSrc === 'object' && videoSrc !== null ? (videoSrc as any)?.objectFit || 'cover' : 'cover';
                        
                        return videoSrcString ? (
                          <video
                            ref={(el) => { if (el) videoRefs.current[index] = el; }}
                            className="w-full h-full"
                            style={{ objectFit: videoObjectFit }}
                            autoPlay
                            muted
                            loop
                            playsInline
                            src={videoSrcString}
                          >
                            Your browser does not support the video tag.
                          </video>
                        ) : null;
                      })()}
                      {showFullscreenButton && (
                        <button
                          onClick={handleFullscreen}
                          className="absolute bottom-4 right-4 p-2 bg-black/50 hover:bg-black/70 text-white rounded-lg backdrop-blur-sm transition-colors"
                        >
                          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" />
                          </svg>
                        </button>
                      )}
                    </div>
                  </div>
                )}
              </div>
            ))}
          </div>

          {/* Desktop Video Display */}
          <div className="hidden md:block relative">
            {tabs.map((tab, index) => (
              <div
                key={tab.id}
                className={`${activeTab === index ? 'block' : 'hidden'}`}
              >
                <div className="relative aspect-video bg-black">
                  {(() => {
                    const videoSrc = tab.videoSrc;
                    const videoSrcString = typeof videoSrc === 'string' ? videoSrc : (videoSrc as any)?.src || '';
                    const videoObjectFit = typeof videoSrc === 'object' && videoSrc !== null ? (videoSrc as any)?.objectFit || 'cover' : 'cover';
                    
                    return videoSrcString ? (
                      <video
                        ref={(el) => { if (el) videoRefs.current[index] = el; }}
                        className="w-full h-full"
                        style={{ objectFit: videoObjectFit }}
                        autoPlay={autoplay}
                        muted
                        loop
                        playsInline
                        src={videoSrcString}
                      >
                        Your browser does not support the video tag.
                      </video>
                    ) : null;
                  })()}
                  {showFullscreenButton && (
                    <button
                      onClick={handleFullscreen}
                      className="absolute bottom-6 right-6 p-3 bg-black/50 hover:bg-black/70 text-white rounded-xl backdrop-blur-sm transition-all hover:scale-110"
                      title="Fullscreen"
                    >
                      <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4" />
                      </svg>
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}
